import { UnreachableError } from '../../base/preconditions';
import murmurhash from 'murmurhash';
let flags;
let flagOverrides;
let interceptors;
export const urlParamPrefix = 'flag.';
export function featureFlag(name, defaultValue) {
    if (flags == null) {
        const maybeFlags = typeof self !== 'undefined' ? self['flags'] : undefined;
        flags = {
            ...(maybeFlags || {})
        };
        if (featureFlag('fe634b10', false))
            flagOverrides = getFlagOverridesFromUrlParams();
    }
    const maybeOverrideValue = flagOverrides?.[name];
    if (maybeOverrideValue != null) {
        delete flagOverrides[name];
        switch(typeof defaultValue){
            case 'boolean':
                flags[name] = maybeOverrideValue === '' || maybeOverrideValue === 'true';
                break;
            case 'number':
                flags[name] = Number(maybeOverrideValue);
                break;
            case 'string':
                flags[name] = maybeOverrideValue;
                break;
            default:
                throw new UnreachableError(defaultValue);
        }
    }
    if (interceptors) for (const interceptor of interceptors){
        const mockValue = interceptor(name, defaultValue, flags);
        if (mockValue != null) return mockValue;
    }
    return flags[name] ?? defaultValue;
}
function getFlagOverridesFromUrlParams() {
    const flagOverridesFromUrlParams = {};
    const urlParams = new URLSearchParams(self?.location?.search ?? '');
    for (const [maybeFlag, maybeOverrideValue] of urlParams){
        const match = maybeFlag.match(/^flags?\.(.+)$/i);
        if (match) flagOverridesFromUrlParams[DO_NOT_USE_hashFlagName(match[1])] = maybeOverrideValue;
    }
    return flagOverridesFromUrlParams;
}
export function DO_NOT_USE_hashFlagName(identifier) {
    return murmurhash.v3(identifier, 314159).toString(16);
}
export function DO_NOT_USE_addInterceptor(interceptor, onDispose) {
    (interceptors ?? (interceptors = [])).unshift(interceptor);
    let isDisposed = false;
    return ()=>{
        if (!interceptors || isDisposed) return;
        interceptors.splice(interceptors.indexOf(interceptor), 1);
        isDisposed = true;
        onDispose?.();
    };
}
